VALUES
  ('dietitian-moex-07164', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關鯖魚中毒（scombroid fish poisoning）之敘述，下列何者錯誤？ 鯖科魚魚肉中的離胺酸經分解產生胺類物質而造成 鯖魚等相關魚種經捕獲後未冷藏、冷凍或不新鮮的魚體經食用後易發生此類中毒 中毒症狀包括臉部及四肢潮紅、皮膚癢、心悸等，是一種類過敏性食物中毒 人體具有解毒酵素以分解食入的少量毒性物質', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07165', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關仙人掌桿菌之敘述，下列何者錯誤？ 是米飯及馬鈴薯等澱粉性食物常見之中毒菌  被污染的食物不包括肉類及牛乳 可能會分泌毒素    會產生孢子', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07166', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者不是植物性產氰醣苷（cyanogenic glycosides）？ 苦杏仁苷（amygdalin）   亞麻苦苷（linamarin） 原甲狀腺苷（progoitrin）  玉米苷（dhurrin）', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07167', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '關於農藥殘留之敘述，下列何者錯誤？ 有機磷殺蟲劑化性穩定、不易分解，比有機氯殺蟲劑的殘留時間長 連續性採收或提前採收的蔬菜，農藥殘留的風險較高 葉菜類比根菜類農藥殘留的機率大 清洗、去皮等處理方式，都可減少農藥殘留', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07168', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者為產生腎臟病變之黃變米毒素？ citerovirdin  citrinin  trichothecene  luteoskyrin', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 30, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07169', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關「定位清洗法」的敘述，下列何者正確？ 洗能看到及接觸到的機器外部，簡稱CIP 以不拆卸機器為原則而洗管線內部 因配合高流速或強力噴灑方式進行，因此完全無清洗上的死角 在美國稱為CH，在歐洲各國稱為OPC', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07170', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關餐飲業廢棄物的分類處理，下列敘述何者錯誤？ 盛裝酸、鹼、漂白水的容器是屬於有害廢棄物  衛生筷屬於可回收廢棄物 玻璃瓶屬於可回收廢棄物  塑膠瓶與塑膠袋屬於不可回收廢棄物', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 32, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
