  ('dietitian-moex-07173', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '餐具經過消毒與風乾後，應儲存於下列何區？ 準清潔區  一般工作區  污染區  清潔區', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
